// Generic function with constraint
func clamp<T: Comparable>(_ value: T, to range: ClosedRange<T>) -> T {
  min(max(value, range.lowerBound), range.upperBound)
}

// Generic type
struct Stack<Element> {
  private var storage: [Element] = []
  mutating func push(_ x: Element) { storage.append(x) }
  mutating func pop() -> Element? { storage.popLast() }
  var top: Element? { storage.last }
}
var s = Stack<Int>(); s.push(1); s.push(2)

// Where clause — extension scoped by element constraint
extension Stack where Element: Equatable {
  func contains(_ x: Element) -> Bool { storage.contains(x) }
}

// Multiple constraints + same-type requirement
func zip2<C1: Collection, C2: Collection>(
  _ a: C1,
  _ b: C2
) -> [(C1.Element, C2.Element)] where C1.Element: Equatable, C1.Element == C2.Element {
  Array(zip(a, b))
}

// Generic + protocol w/ associated type
func total<C: Collection>(_ c: C) -> Int where C.Element == Int { c.reduce(0, +) }

// Type erasure with AnySequence/AnyHashable when generics get unwieldy
