// Define a wrapper
@propertyWrapper
struct Clamped<Value: Comparable> {
  private var value: Value
  let range: ClosedRange<Value>
  init(wrappedValue: Value, _ range: ClosedRange<Value>) {
    self.range = range
    self.value = min(max(wrappedValue, range.lowerBound), range.upperBound)
  }
  var wrappedValue: Value {
    get { value }
    set { value = min(max(newValue, range.lowerBound), range.upperBound) }
  }
}

struct Volume {
  @Clamped(0...100) var level: Int = 50
}
var v = Volume()
v.level = 200
print(v.level) // 100 — clamped

// projectedValue — exposed via $
@propertyWrapper
struct Trimmed {
  private var value: String = ""
  var wrappedValue: String {
    get { value }
    set { value = newValue.trimmingCharacters(in: .whitespaces) }
  }
  var projectedValue: Int { value.count }
}

struct Form { @Trimmed var name: String }
var f = Form(); f.name = "  Alice  "
print(f.name)  // "Alice"
print(f.$name) // 5  — projected via $

