// A toy HTML builder DSL
@resultBuilder
struct HTMLBuilder {
  static func buildBlock(_ parts: String...) -> String {
    parts.joined()
  }
  static func buildOptional(_ part: String?) -> String { part ?? "" }
  static func buildEither(first: String) -> String { first }
  static func buildEither(second: String) -> String { second }
  static func buildArray(_ parts: [String]) -> String { parts.joined() }
}

func html(@HTMLBuilder content: () -> String) -> String { content() }
func tag(_ name: String, @HTMLBuilder _ content: () -> String) -> String {
  "<\(name)>\(content())</\(name)>"
}

let page = html {
  tag("h1") { "Hello" }
  if true {
    tag("p") { "Conditionally rendered" }
  }
  for i in 1...3 {
    tag("li") { "Item \(i)" }
  }
}
print(page)
// <h1>Hello</h1><p>Conditionally rendered</p><li>Item 1</li>...

