struct User { var name: String; var age: Int }
let users = [User(name: "Alice", age: 30), User(name: "Bob", age: 25)]

// Key path literal
let kp = \User.name      // KeyPath<User, String>
print(users[0][keyPath: kp]) // Alice

// Generic helper using key paths
extension Sequence {
  func sorted<Value: Comparable>(by kp: KeyPath<Element, Value>) -> [Element] {
    sorted { $0[keyPath: kp] < $1[keyPath: kp] }
  }
  func grouped<Key: Hashable>(by kp: KeyPath<Element, Key>) -> [Key: [Element]] {
    Dictionary(grouping: self, by: { $0[keyPath: kp] })
  }
}

let byAge = users.sorted(by: \.age)
let byName = users.grouped(by: \.name)

